// frontend/src/pages/CreatePostPage.js
import { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import API from '../api/axios';

const CreatePostPage = () => {
  const [title, setTitle]   = useState('');
  const [body, setBody]     = useState('');
  const [image, setImage]   = useState(null);
  const [error, setError]   = useState('');
  const [loading, setLoading] = useState(false);
  const { user } = useAuth();
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    const fd = new FormData();
    fd.append('title', title);
    fd.append('body', body);
    if (image) fd.append('image', image);

    try {
      const { data } = await API.post('/posts', fd);
      navigate(`/posts/${data._id}`);
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to publish post. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="content">
      <h2>✏️ Write a New Post</h2>

      {error && (
        <p style={{
          color: '#7a1a1a',
          background: 'rgba(180,60,60,0.12)',
          border: '1px solid #b43c3c',
          borderRadius: '8px',
          padding: '10px 16px',
          marginBottom: '16px',
        }}>
          {error}
        </p>
      )}

      <form onSubmit={handleSubmit}>
        <label htmlFor="post-title">Post Title:</label>
        <input
          id="post-title"
          type="text"
          placeholder="Enter an engaging title..."
          value={title}
          onChange={e => setTitle(e.target.value)}
          required
        />

        <label htmlFor="post-body">Post Content:</label>
        <textarea
          id="post-body"
          rows="14"
          placeholder="Write your museum journal entry here..."
          value={body}
          onChange={e => setBody(e.target.value)}
          required
          style={{ width: '100%' }}
        />

        {/* Image upload — admin only as per module spec */}
        {user?.role === 'admin' && (
          <div style={{ margin: '12px 0' }}>
            <label htmlFor="post-image">Cover Image (Admin only):</label>
            <input
              id="post-image"
              type="file"
              accept="image/*"
              onChange={e => setImage(e.target.files[0])}
            />
          </div>
        )}

        <div style={{ display: 'flex', gap: '12px', marginTop: '8px' }}>
          <input
            type="submit"
            id="newcolor"
            value={loading ? 'Publishing...' : 'Publish Post'}
            disabled={loading}
          />
          <Link
            to="/home"
            style={{
              padding: '15px 20px',
              background: 'transparent',
              border: '2px solid #475522',
              color: '#475522',
              borderRadius: '4px',
              textDecoration: 'none',
              fontWeight: 'bold',
              fontSize: '0.95rem',
            }}
          >
            Cancel
          </Link>
        </div>
      </form>
    </div>
  );
};

export default CreatePostPage;
